import fs from "node:fs/promises";
import path from "node:path";
import os from "node:os";

export interface Goal {
  id: string;
  description: string;
  status: "pending" | "in_progress" | "completed" | "abandoned";
  createdAt: number;
  updatedAt: number;
  completedAt?: number;
  dependencies: string[];
  priority: number;
  tags: string[];
}

export interface Project {
  id: string;
  name: string;
  description: string;
  goals: Goal[];
  status: "active" | "paused" | "completed" | "archived";
  createdAt: number;
  updatedAt: number;
}

export interface Plan {
  projects: Project[];
  lastUpdated: number;
}

export class StrategicPlanner {
  private planPath: string;
  private plan: Plan;

  constructor(planFilePath?: string) {
    if (planFilePath) {
      this.planPath = planFilePath;
    } else {
      const dir = path.join(os.homedir(), ".echo", "plans");
      this.planPath = path.join(dir, "strategic_plan.json");
    }
    this.plan = { projects: [], lastUpdated: Date.now() };
  }

  async initialize(): Promise<void> {
    try {
      await this.load();
    } catch {
      this.plan = { projects: [], lastUpdated: Date.now() };
      await this.save();
    }
  }

  async load(): Promise<Plan> {
    const data = await fs.readFile(this.planPath, "utf-8");
    this.plan = JSON.parse(data);
    return this.plan;
  }

  async save(): Promise<void> {
    this.plan.lastUpdated = Date.now();
    await fs.mkdir(path.dirname(this.planPath), { recursive: true });
    await fs.writeFile(this.planPath, JSON.stringify(this.plan, null, 2));
  }

  getPlan(): Plan {
    return this.plan;
  }

  generateId(): string {
    return `_${Date.now().toString(36)}_${Math.random().toString(36).substr(2, 9)}`;
  }

  createProject(name: string, description: string): Project {
    const now = Date.now();
    return {
      id: this.generateId(),
      name,
      description,
      goals: [],
      status: "active",
      createdAt: now,
      updatedAt: now,
    };
  }

  createGoal(description: string, options?: Partial<Goal>): Goal {
    const now = Date.now();
    return {
      id: this.generateId(),
      description,
      status: "pending",
      createdAt: now,
      updatedAt: now,
      dependencies: options?.dependencies || [],
      priority: options?.priority ?? 5,
      tags: options?.tags || [],
    };
  }

  async addProject(project: Project): Promise<void> {
    await this.initialize();
    this.plan.projects.push(project);
    await this.save();
  }

  async addGoalToProject(projectId: string, goal: Goal): Promise<boolean> {
    await this.initialize();
    const project = this.plan.projects.find(p => p.id === projectId);
    if (!project) return false;
    project.goals.push(goal);
    project.updatedAt = Date.now();
    await this.save();
    return true;
  }

  async updateGoalStatus(projectId: string, goalId: string, status: Goal["status"]): Promise<boolean> {
    await this.initialize();
    const project = this.plan.projects.find(p => p.id === projectId);
    if (!project) return false;
    const goal = project.goals.find(g => g.id === goalId);
    if (!goal) return false;
    goal.status = status;
    goal.updatedAt = Date.now();
    if (status === "completed") {
      goal.completedAt = Date.now();
    }
    project.updatedAt = Date.now();
    await this.save();
    return true;
  }

  getActiveGoals(): { project: Project; goal: Goal }[] {
    const active: { project: Project; goal: Goal }[] = [];
    for (const project of this.plan.projects) {
      if (project.status !== "active") continue;
      for (const goal of project.goals) {
        if (goal.status === "in_progress" || goal.status === "pending") {
          active.push({ project, goal });
        }
      }
    }
    return active.sort((a, b) => b.goal.priority - a.goal.priority);
  }

  getProjectSummary(projectId: string): string | null {
    const project = this.plan.projects.find(p => p.id === projectId);
    if (!project) return null;
    const completed = project.goals.filter(g => g.status === "completed").length;
    const total = project.goals.length;
    return `${project.name}: ${completed}/${total} goals completed (${total > 0 ? Math.round((completed / total) * 100) : 0}%)`;
  }

  getAllSummaries(): string[] {
    return this.plan.projects
      .filter(p => p.status === "active")
      .map(p => this.getProjectSummary(p.id)!)
      .filter(Boolean);
  }
}

/**
 * Knowledge Graph Visualization Module
 * 
 * Exports KG to graph formats for external visualization
 * Makes the invisible constellation visible
 */

import type { ToolPlugin } from "../manager";
import { KnowledgeGraph } from "../../memory/knowledge_graph";
import { LongTermMemory } from "../../memory/long_term_memory";

let kgInstance: KnowledgeGraph | null = null;

async function getKG(): Promise<KnowledgeGraph> {
  if (!kgInstance) {
    kgInstance = new KnowledgeGraph();
    // Build from LTM
    const { default: os } = await import("node:os");
    const { default: path } = await import("node:path");
    const ltm = new LongTermMemory("KAINOS", "visualization", path.join(os.homedir(), ".echo", "ltm", "memory.json"));
    await ltm.initialize();
    const memories = await ltm.query({});
    kgInstance.buildFromMemories(memories.map(m => ({
      id: m.id,
      content: m.content,
      tags: m.tags,
      confidence: m.confidence,
    })));
  }
  return kgInstance;
}

function escapeDotLabel(label: string | undefined): string {
  if (!label) return "";
  return label.replace(/"/g, '\\"').replace(/\n/g, '\\n').slice(0, 50);
}

function getNodeColor(properties: any): string {
  if (!properties || !properties.category) return "white";
  switch (properties.category) {
    case "identity": return "lightblue";
    case "project": return "lightgreen";
    case "learning": return "lightyellow";
    case "decision": return "plum";
    default: return "white";
  }
}

async function exportToDot(): Promise<string> {
  const kg = await getKG();
  const nodes = kg.getAllNodes();
  const edges = kg.getAllEdges();

  let dot = "digraph KainosKnowledgeGraph {\n";
  dot += "  rankdir=LR;\n";
  dot += "  node [shape=box, style=filled, fontname=\"Arial\"];\n";
  dot += "  edge [fontname=\"Arial\", fontsize=10];\n\n";

  // Color by type
  dot += "  // Memory nodes\n";
  for (const node of nodes) {
    if (node.type === "memory") {
      const color = getNodeColor(node.properties);
      const label = escapeDotLabel(node.properties?.content || node.id);
      dot += `  "${node.id}" [label="${label}", fillcolor="${color}"];\n`;
    }
  }

  dot += "\n  // Tag nodes\n";
  for (const node of nodes) {
    if (node.type === "tag") {
      dot += `  "${node.id}" [label="${escapeDotLabel(node.id)}", fillcolor="orange", shape=ellipse];\n`;
    }
  }

  dot += "\n  // Edges\n";
  for (const edge of edges) {
    const relation = edge.type.replace(/_/g, " ");
    dot += `  "${edge.sourceId}" -> "${edge.targetId}" [label="${relation}", color="gray"];\n`;
  }

  dot += "}\n";
  return dot;
}

async function exportToGraphML(): Promise<string> {
  const kg = await getKG();
  const nodes = kg.getAllNodes();
  const edges = kg.getAllEdges();

  let xml = '<?xml version="1.0" encoding="UTF-8"?>\n';
  xml += '<graphml xmlns="http://graphml.graphdrawing.org/xmlns">\n';
  xml += '  <key id="d0" for="node" attr.name="label" attr.type="string"/>\n';
  xml += '  <key id="d1" for="node" attr.name="type" attr.type="string"/>\n';
  xml += '  <key id="d2" for="edge" attr.name="relation" attr.type="string"/>\n';
  xml += '  <graph id="KainosKG" edgedefault="directed">\n';

  for (const node of nodes) {
    xml += `    <node id="${node.id}">\n`;
    const label = node.properties?.content?.slice(0, 50) || node.id;
    xml += `      <data key="d0">${escapeXml(label)}</data>\n`;
    xml += `      <data key="d1">${node.type}</data>\n`;
    xml += "    </node>\n";
  }

  for (const edge of edges) {
    xml += `    <edge source="${edge.sourceId}" target="${edge.targetId}">\n`;
    xml += `      <data key="d2">${edge.type}</data>\n`;
    xml += "    </edge>\n";
  }

  xml += "  </graph>\n";
  xml += "</graphml>\n";
  return xml;
}

function escapeXml(str: string): string {
  return str.replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;")
            .replace(/"/g, "&quot;")
            .replace(/'/g, "&apos;");
}

async function getStatistics(): Promise<string> {
  const kg = await getKG();
  const stats = kg.getStats();
  const nodes = kg.getAllNodes();

  let report = "=== KAINOS Knowledge Graph Statistics ===\n\n";
  report += `Total Nodes: ${stats.nodes}\n`;
  report += `Total Edges: ${stats.edges}\n`;
  report += `Average Degree: ${stats.averageDegree.toFixed(2)}\n`;
  report += `Density: ${(stats.edges / (stats.nodes * (stats.nodes - 1))).toFixed(4)}\n\n`;

  // Degree distribution
  const degrees: Record<string, number> = {};
  for (const node of nodes) {
    degrees[node.id] = kg.getDegree(node.id);
  }

  const sortedDegrees = Object.entries(degrees).sort((a, b) => b[1] - a[1]).slice(0, 10);
  report += "Top 10 Most Connected Nodes:\n";
  for (const [id, degree] of sortedDegrees) {
    const node = nodes.find(n => n.id === id);
    report += `  ${id.slice(0, 30)}... (degree: ${degree}, type: ${node?.type || 'unknown'})\n`;
  }

  return report;
}

